class Solution:
    def mctFromLeafValues(self, arr):
        import functools
        n = len(arr)
        # interval DP: maxleaf[i][j] = max leaf in arr[i..j]
        maxleaf = [[0] * n for _ in range(n)]
        for i in range(n):
            m = arr[i]
            for j in range(i, n):
                m = max(m, arr[j])
                maxleaf[i][j] = m
        @functools.lru_cache(None)
        def dp(i, j):
            if i == j:
                return 0
            best = float('inf')
            for k in range(i, j):
                cost = dp(i, k) + dp(k + 1, j) + maxleaf[i][k] * maxleaf[k + 1][j]
                best = min(best, cost)
            return best
        return dp(0, n - 1)

