class Solution:
    def mctFromLeafValues(self, arr):
        stack = [float('inf')]
        total = 0
        for x in arr:
            while stack[-1] <= x:
                mid = stack.pop()
                total += mid * min(stack[-1], x)
            stack.append(x)
        while len(stack) > 2:
            total += stack.pop() * stack[-1]
        return total

