var mctFromLeafValues = function(arr) {
    const stack = [Infinity];
    let total = 0;
    for (const x of arr) {
        while (stack[stack.length - 1] <= x) {
            const mid = stack.pop();
            total += mid * Math.min(stack[stack.length - 1], x);
        }
        stack.push(x);
    }
    while (stack.length > 2) {
        total += stack.pop() * stack[stack.length - 1];
    }
    return total;
};
